			const event = payload.event || message.key?.toString();
			switch (event) {
				case kafkaEvents.FETCH_REPORT_DATA:
					validateMessage(schema.fetchReportData, payload);
					await this.fetchReportData(payload);
					break;

				default:
					break;
			}
		} catch (error) {
			throw error;
		}
	}

