				.select("data_invites.*")
				.where({ "data_invites.case_id": params.caseID })
				.andWhere({ "db.is_deleted": false })
				.whereNotNull("data_invites.metadata")
				.orderBy("public.data_invites.created_at", "desc")
				.limit(1)
		]);

.andWhere({ "db.is_deleted": false })
