					value: VALUE_NOT_AVAILABLE,
				},
				{
					label: "Status",
					value: VALUE_NOT_AVAILABLE,
					badge: {
						text: "Unknown",

{
					label: "Status",
					value: VALUE_NOT_AVAILABLE,
					badge: {
						text: "Unknown",
						variant: "secondary",
						icon: null,
					},
				},
			];
		}

		if (!websiteData) {
